var input = inputs.Length > 0 ? inputs[0] : null;
if (input is null)
    return PixelBuffer.CreateSolid(context.TileSize, context.TileSize, 0, 0, 0);

var levels = GetInt(parameters, "levels", 8);
var independentChannels = GetBool(parameters, "independentChannels");

var result = input.Clone();
var steps = levels - 1;

if (independentChannels)
{
    result.Apply((r, g, b, a) =>
    {
        r = MathF.Round(r * steps) / steps;
        g = MathF.Round(g * steps) / steps;
        b = MathF.Round(b * steps) / steps;
        return (r, g, b, a);
    });
}
else
{
    // Compute grayscale luminance first, quantize that, then map all channels to same level
    result.Apply((r, g, b, a) =>
    {
        var lum = 0.2126f * r + 0.7152f * g + 0.0722f * b;
        var quantized = MathF.Round(lum * steps) / steps;
        return (quantized, quantized, quantized, a);
    });
}

return result;
}
